@[grind <=]
lemma mem_orIntroL [Entailment.HasAxiomOrInst L] (hφ : φ ∈ T.theory) : φ ⋎ ψ ∈ T.theory := by
  apply T.imp_closed (φ := φ);
  . exact orIntroL;
  . assumption;

@[grind <=]
