import Foundation.Propositional.Hilbert.F.Deduction
import Foundation.Propositional.Kripke2.Basic

namespace LO.Propositional

open LO.Entailment (disjunctive)
open LO.Propositional.Entailment.Corsi
open Formula

variable {α : Type*}
variable {S} [Entailment S (Formula α)]
variable {𝓢 : S}

structure FTheory (L : Logic ℕ) where
  protected theory : FormulaSet ℕ
  protected no_bot : ⊥ ∉ theory
  protected andIR : ∀ {φ ψ}, φ ∈ theory → ψ ∈ theory → φ ⋏ ψ ∈ theory
  protected imp_closed : ∀ {φ ψ}, L ⊢ φ ➝ ψ → φ ∈ theory → ψ ∈ theory
  protected L_subset : L ⊆ theory


namespace FTheory

attribute [simp] FTheory.no_bot
attribute [grind <=] FTheory.andIR FTheory.imp_closed

variable {T : FTheory L} {φ ψ χ : Formula ℕ}

@[simp, grind <=]
lemma mem_of_provable [Entailment.HasAxiomVerum L] [Entailment.AFortiori L] (hφ : L ⊢ φ) : φ ∈ T.theorem := by
  apply T.imp_closed (φ := ⊤) $ af hφ;
  apply T.L_subset;
  apply Logic.iff_provable.mp;
  simp;

lemma mem_trans [Entailment.HasAxiomI L] (h₁ : φ ➝ ψ ∈ T.theorem) (h₂ : ψ ➝ χ ∈ T.theorem) : φ ➝ χ ∈ T.theorem := by
  apply T.imp_closed (axiomI (ψ := ψ));
  apply T.∧IR h₁ h₂;

@[grind <=]
lemma mem_orIntroL [Entailment.HasAxiomOrInst L] (hφ : φ ∈ T.theorem) : φ ⋎ ψ ∈ T.theorem := by
  apply T.imp_closed (φ := φ);
  . exact orIntroL;
  . assumption;

@[grind <=]
lemma mem_orIntroR [Entailment.HasAxiomOrInst L] (hψ : ψ ∈ T.theorem) : φ ⋎ ψ ∈ T.theorem := by
  apply T.imp_closed (φ := ψ);
  . exact orIntroR;
  . assumption;

open Hilbert.F in
lemma iff_mem_CorsiDeducible {T : FTheory (Hilbert.F Ax)} : φ ∈ T.theorem ↔ Deduction Ax T.theorem φ := by
  constructor;
  . intro hφ;
    apply Deduction.ctx hφ;
  . intro h; induction h <;> grind

end FTheory


variable {L : Logic ℕ}

structure PrimeFTheory (L : Logic ℕ) extends FTheory L where
  protected prime : ∀ {φ ψ}, φ ⋎ ψ ∈ theory → φ ∈ theory ∨ ψ ∈ theory

namespace FTheory.lindenbaum

open Classical
open Encodable

variable {φ ψ χ ξ : Formula ℕ} {T : FTheory L} {hT : χ ➝ ξ ∉ T.theorem}

def construction (T : FTheory L) (hT : χ ➝ ξ ∉ T.theorem) : ℕ → Set (Formula ℕ)
  | 0 => { δ | χ ➝ δ ∈ T.theorem }
  | i + 1 =>
    match (decode i) with
    | some δ =>
      letI T' := construction T hT i
      if ∀ Γ : Finset (Formula _), ↑Γ ⊆ T' → Γ.conj ⋏ δ ➝ ξ ∉ T.theorem then insert δ T'
      else T'
    | none => construction T hT i

def construction_omega (T : FTheory L) (hT : χ ➝ ξ ∉ T.theorem) : Set (Formula ℕ) := ⋃ i, construction T hT i

lemma subset_construction_succ : construction T hT i ⊆ construction T hT (i + 1) := by
  dsimp [construction];
  split;
  . split <;> tauto;
  . tauto;

lemma subset_construction_add : construction T hT i ⊆ construction T hT (i + j) := by
  induction j with
  | zero => simp;
  | succ j ih =>
    trans construction T hT (i + j);
    . apply ih;
    . apply subset_construction_succ;

lemma monotone_construction (hij : i ≤ j) : construction T hT i ⊆ construction T hT j := by
  obtain ⟨k, rfl⟩ := le_iff_exists_add.mp hij;
  apply subset_construction_add;

