  (χ ➝ φ ∈ T.theorem) ∨ (∀ Γ : Finset _, ↑Γ ⊆ construction T hT (encode φ) → Γ.conj ⋏ φ ➝ ξ ∉ T.theorem) := by
  obtain ⟨i, hi⟩ := by simpa [construction_omega] using hφ;
  induction i with
  | zero => left; simpa [construction] using hi;
  | succ i ih =>
    dsimp [construction] at hi;
    sorry;
