  intro i;
  induction i with
  | zero =>
    simp [construction];
    sorry;
  | succ i ih =>
    simp [construction];
    split;
    . split_ifs with h;
      . rename_i δ hδ;
        by_contra hC;
        have : δ = φ := by grind;
        subst this;
        apply h Γ ((show encode δ = i by sorry) ▸ hΓ) hφ;
      . assumption
    . assumption;

lemma of_not_mem_construction_omega {φ : Formula ℕ} (hφ : φ ∉ construction_omega T hT) :
  (χ ➝ φ ∉ T.theorem) ∧ (∃ Γ : Finset (Formula _), ↑Γ ⊆ (construction T hT (encode φ)) ∧ Γ.conj ⋏ φ ➝ ξ ∈ T.theorem) := by
  simp only [construction_omega, Set.mem_iUnion, not_exists] at hφ;
